const { CosmosClient } = require("@azure/cosmos");
const { AzureFunction, Context } = require("azure-functions");

const cosmosClient = new CosmosClient({ endpoint: "https://your-cosmosdb-account.documents.azure.com", key: "your-key" });

module.exports = AzureFunction(async function (context) {
  const collection = cosmosClient.database("your-database").collection("your-collection");

  // Set the function timeout to maximum (10 minutes for Consumption plan)
  context.timeout = 600000;

  // Disable timeout enforcement where possible
  if (context.executionContext.functionName === "your-function-name") {
    context.timeout = null;
  }

  // Process large datasets from Cosmos DB
  const querySpec = {
    query: "SELECT * FROM c",
  };

  try {
    const result = await collection.query(querySpec).fetchAll();

    // Focus on completing processing without interruption
    for (const item of result) {
      // Process each item in the dataset
      console.log(item);
    }
  } catch (err) {
    context.log.error("Error:", err);
  }
});